def find_duplicates(ledgers):
    duplicates = []
    for i in range(len(ledgers)):
        for j in range(i + 1, len(ledgers)):
            if ledgers[i] == ledgers[j] and ledgers[i] not in duplicates:
                duplicates.append(ledgers[i])
    return duplicates

