public boolean hasPairSum(int[] measurements, int target) {
    for (int i = 0; i < measurements.length; i++) {
        for (int j = i + 1; j < measurements.length; j++) {
            if (measurements[i] + measurements[j] == target) return true;
        }
    }
    return false;
}

