int mostFrequent(vector<int>& signals) {
    int maxCount = 0, result = signals[0];
    for (int i = 0; i < signals.size(); i++) {
        int count = 0;
        for (int j = 0; j < signals.size(); j++) {
            if (signals[j] == signals[i]) count++;
        }
        if (count > maxCount) { maxCount = count; result = signals[i]; }
    }
    return result;
}

