public List<List<String>> groupAnagrams(String[] packets) {
    List<List<String>> result = new ArrayList<>();
    boolean[] visited = new boolean[packets.length];
    for (int i = 0; i < packets.length; i++) {
        if (visited[i]) continue;
        List<String> group = new ArrayList<>();
        group.add(packets[i]);
        for (int j = i + 1; j < packets.length; j++) {
            char[] a = packets[i].toCharArray();
            char[] b = packets[j].toCharArray();
            Arrays.sort(a); Arrays.sort(b);
            if (Arrays.equals(a, b)) { group.add(packets[j]); visited[j] = true; }
        }
        result.add(group);
    }
    return result;
}

